// GET devolve { unidades: [...] } — vira 1 item por unidade em
// risco pros próximos nodes processarem individualmente. Lista
// vazia (ninguém em risco hoje) ⇒ zero itens ⇒ cadeia para aqui,
// nenhum e-mail sai.
return ($input.first().json.unidades || []).map((u) => ({ json: u }));

// Junta o diagnóstico do Claude com os KPIs da unidade (mesmo
// índice de item = mesma unidade, pareamento automático do n8n).
// Se a Claude API falhar/vier vazia, cai no fallback factual — o
// alerta nunca deixa de sair por causa da IA.
const kpis = $("Explode unidades em risco").item.json;
const diagnostico = ($json.content?.[0]?.text || '').trim()
  || `Unidade ${kpis.unidade_nome} em ${kpis.pct_meta}% da meta com ${kpis.dias_restantes} dias restantes.`;
return { json: { ...kpis, diagnostico } };

